INSERT INTO `livros` (`id`, `nome`, `autor`, `ano_publicacao`, `id_categoria`, `sinopse`, `capa`) VALUES
(1, 'A Fundação', 'Isaac Asimov', 1951, 1, 'Há doze mil anos, o Império Galáctico reina, absoluto, sobre todos os mundos habitados. Mas esse reinado ignora um futuro terrível: uma crise levará a humanidade a uma era sombria de ignorância e barbárie que se estenderá por milênios.\nO único homem a prever a tragédia é Hari Seldon, que a partir de uma ciência recém-descoberta, a psico-história, cria um plano para preservar todo o conhecimento humano e evitar o declínio da civilização. Esse plano será a última esperança da humanidade e deverá ser colocado em prática, através dos séculos, pelos membros da Fundação.\nPublicado originalmente em 1951, Fundação permite o encontro da grandiosidade temática inspirada por Declínio e queda do Império Romano, de Edward Gibbon, e as situações únicas de exploração do cenário galáctico e futurístico, retratando como isso reflete nos caminhos da humanidade.\n', 0x433a78616d70706874646f637356656e75734361706173312e46756e6461c3a7c3a36f2e6a7067),
(2, 'Duna', 'Frank Herbert', 1965, 1, 'O Céu sobre o porto tinha cor de televisão num canal fora do ar. Considerada a obra precursora do movimento cyberpunk e um clássico da ficção científica moderna, Neuromancer conta a história de Case, um cowboy do ciberespaço e hacker da matrix. Como punição por tentar enganar os patrões, seu sistema nervoso foi contaminado por uma toxina que o impede de entrar no mundo virtual. Agora, ele vaga pelos subúrbios de Tóquio, cometendo pequenos crimes para sobreviver, e acaba se envolvendo em uma jornada que mudará para sempre o mundo e a percepção da realidade. Evoluindo de Blade Runner e antecipando Matrix, Neuromancer é o romance de estreia de William Gibson. Esta obra distópica, publicada em 1984, antevê, de modo muito preciso, vários aspectos fundamentais da sociedade atual e de sua relação com a tecnologia. Foi o primeiro livro a ganhar a chamada “tríplice coroa da ficção científica”: os prestigiados prêmios Hugo, Nebula e Philip K. Dick.\n', 0x433a78616d70706874646f637356656e75734361706173322e44756e612e6a7067),
(3, 'Neuromancer', 'William Gibson', 1984, 1, ' O Céu sobre o porto tinha cor de televisão num canal fora do ar. Considerada a obra precursora do movimento cyberpunk e um clássico da ficção científica moderna, Neuromancer conta a história de Case, um cowboy do ciberespaço e hacker da matrix. Como punição por tentar enganar os patrões, seu sistema nervoso foi contaminado por uma toxina que o impede de entrar no mundo virtual. Agora, ele vaga pelos subúrbios de Tóquio, cometendo pequenos crimes para sobreviver, e acaba se envolvendo em uma jornada que mudará para sempre o mundo e a percepção da realidade. Evoluindo de Blade Runner e antecipando Matrix, Neuromancer é o romance de estreia de William Gibson. Esta obra distópica, publicada em 1984, antevê, de modo muito preciso, vários aspectos fundamentais da sociedade atual e de sua relação com a tecnologia. Foi o primeiro livro a ganhar a chamada “tríplice coroa da ficção científica”: os prestigiados prêmios Hugo, Nebula e Philip K. Dick.\n', 0x433a78616d70706874646f637356656e75734361706173332e6e6575726f6d616e6365722e6a7067),
(4, '2001: Uma Odisseia no Espaço', 'Arthur C. Clarke', 1968, 1, 'No alvorecer da humanidade, a fome e os predadores já ameaçavam de extinção...', 0x433a78616d70706874646f637356656e75734361706173342e3230303120756d61206f64697373656961206e6f2065737061c3a76f2e6a7067),
(5, 'O Fim da Eternidade', 'Isaac Asimov', 1955, 1, 'Andrew Harlan é um Eterno: membro da classe dominante do futuro. Seu trabalho é viajar pelos séculos monitorando e alterando realidades, corrigindo assim os erros dos homens. A humanidade estava a salvo. Até que Harlan comete o pior dos pecados: apaixona-se. Tido como um de seus melhores trabalhos, este clássico nos mostra mais uma vez por que Asimov é considerado o grande mestre da ficção científica moderna.\n', 0x433a78616d70706874646f637356656e75734361706173352e4f2066696d20646120657465726e69646164652e6a7067),
(6, 'O Guia do Mochileiro das Galáxias', 'Douglas Adams', 1979, 1, 'Com mais de 15 milhões de exemplares vendidos, a saga de Arthur Dent pela Galáxia conquistou fãs pelo mundo inteiro. O humor ácido e as tramas surreais de Douglas Adams se tornaram ícones de uma geração e seguem fascinando leitores de todas as idades. Reunindo todos os livros da série em uma edição de luxo, O Guia Definitivo do Mochileiro das Galáxias vai levar você por aventuras improváveis. Pegue sua toalha, divirta-se e não entre em pânico! O Guia do Mochileiro das Galáxias – Segundos antes de a Terra ser destruída, Arthur Dent é salvo por Ford Prefect, um E.T. que fazia pesquisa para a nova edição de O Guia do Mochileiro das Galáxias. Pegando carona numa nave alienígena, os dois dão início a uma alucinante viagem pelo tempo e pelo espaço. O Restaurante no Fim do Universo – Arthur Dent e seus companheiros viajam pela Galáxia em uma busca desesperada por algum lugar para comer. Depois de fazer a refeição mais estranha de suas vidas, eles seguem pelo espaço e acabam descobrindo a questão fundamental sobre a Vida, o Universo e Tudo Mais. A Vida, o Universo e Tudo Mais – Após passar os últimos cinco anos abandonado e sozinho na Terra pré-histórica, Arthur Dent é arrastado para uma nova missão: salvar o Universo dos temíveis e infelizes robôs xenófobos do planeta Krikkit. Até Mais, e Obrigado pelos Peixes! – Depois de viajar pelo Universo, ver o aniquilamento da Terra, participar de guerras interestelares e conhecer criaturas extraordinárias, Arthur Dent está de volta ao seu planeta. E tudo parece estranhamente normal – exceto pelo desaparecimento dos golfinhos. Praticamente Inofensiva – Arthur Dent, Ford Prefect e Tricia McMillan se reencontram após muitos anos vivendo separados. Mas o que deveria ser uma festejada reunião de velhos amigos se transforma numa terrível confusão que põe em risco – mais uma vez – a vida de todos.', 0x433a78616d70706874646f637356656e75734361706173362e4f204775696120446566696e697469766f20446f204d6f6368696c6569726f204461732047616cc3a1786961732e6a7067),
(7, 'Snow Crash', 'Neal Stephenson', 1992, 1, 'Em um futuro distópico, os Estados Unidos como o conhecemos não existe mais..Em um futuro distópico, os Estados Unidos como o conhecemos não existe mais. Após o colapso do governo, o país se dividiu em cidades-estado controladas por corporações privadas, mafiosos e mercenários de todo tipo. Para escapar desse mundo de caos, as pessoas passam a maior parte do tempo no Metaverso, uma realidade virtual onde vivem como avatares. Hiro Protagonist é hacker e trabalha para uma organização mafiosa como entregador de pizza, mas, no Metaverso, é um príncipe samurai. Quando surge um novo e misterioso vírus chamado Snow Crash, que ameaça tanto o mundo físico quanto o cibernético, Hiro parte em uma jornada virtual para encontrá-lo e destruí-lo. Publicado pela primeira vez no Brasil em 2008, Snow Crash foi eleito pela revista Time um dos cem melhores romances de língua inglesa. Retrato assustador de uma sociedade pós-moderna decadente, este livro irônico e ousado combina, a um só tempo, cenários improváveis e totalmente verossímeis.\n', 0x433a78616d70706874646f637356656e75734361706173372e536e6f772043726173682e6a7067),
(8, 'Encontro com Rama', 'Arthur C. Clarke', 1973, 1, ' Após a terrível colisão de um meteorito contra o continente europeu, líderes mundiais e cientistas criaram um sistema de monitoramento para evitar que essas catástrofes voltassem a acontecer. Quase cinquenta anos depois, a humanidade acompanha, alarmada, a chegada de um novo objeto de proporções inimagináveis que avança na direção de nosso Sol. Uma expedição é enviada para explorar o que se imagina ser um meteoro colossal, mas que se revela uma sofisticada construção, repleta de enigmas que desafiam a mente e os conceitos humanos.', 0x433a78616d70706874646f637356656e75734361706173382e456e636f6e74726f20636f6d2052616d612e6a7067),
(9, 'O Homem do Castelo Alto', 'Philip K. Dick', 1962, 1, 'Neste livro que é considerado por muito o melhor trabalho do autor, Dick apresenta um cenário sombrio: a Segunda Guerra Mundial foi vencida pelos Nazistas. O mundo vive sob o domínio da Alemanha e do Japão. Os negros são escravos. Os judeus se escondem sob identidades falsas para não serem completamente exterminados. É nesse contexto que se desenvolvem os dramas de vários personagens. Ao apresentar uma versão alternativa da história, Dick levanta a grande questão: \"O que é a realidade, afinal?\"', 0x433a78616d70706874646f637356656e75734361706173392e4f20486f6d656d20646f2043617374656c6f20416c746f2e6a7067),
(10, 'O Fim da Infância', 'Arthur C. Clarke', 1953, 1, 'Em plena Guerra Fria, enquanto russos e americanos se preparam para a corrida espacial, imensas naves surgem sobre as principais capitais do mundo, revelando um dos grandes mistérios da humanidade: O homem não está sozinho no universo.\nSeus ocupantes, chamados de Senhores Supremos, dominam a Terra de forma pacífica e melhoram substancialmente as condições de vida. A ignorância, a guerra e a pobreza deixam de existir, dando início a uma era de ouro. Porém, uma dúvida assombra a humanidade: quais seriam os verdadeiros objetivos dos Senhores Supremos? Até quando suas políticas iriam coincidir com o bem-estar dos homens? As respostas para essas questões podem revelar uma verdade aterradora\n', 0x433a78616d70706874646f637356656e7573436170617331302e4f2046696d20646120496e66c3a26e6369612e6a7067),
(11, 'The Expanse: Leviathan Wakes', 'James S.A. Corey', 2011, 1, 'A humanidade colonizou o sistema solar – Marte, a Lua, o Cinturão de Asteróides e mais além – mas as estrelas ainda estão fora do nosso alcance.\r\nJim Holden é o comandante de um minerador de gelo que faz viagens dos anéis de Saturno até as estações de mineração do Cinturão. Quando ele e sua tripulação se deparam com um navio abandonado, o Scopuli, eles ficam de posse de um segredo que nunca desejaram. Um segredo pelo qual alguém está disposto a matar – e matar em uma escala incompreensível para Jim e sua equipe. A guerra está se formando no sistema, a menos que ele descubra quem deixou a nave e por quê.\r\nO detetive Miller está procurando uma garota. Uma garota em um sistema de bilhões, mas seus pais têm dinheiro e dinheiro fala. Quando a trilha o leva aos Scopuli e ao simpatizante rebelde Holden, ele percebe que essa garota pode ser a chave para tudo.\r\n', 0x433a78616d70706874646f637356656e7573436170617331312e4c657669617468616e2057616b65732e6a7067),
(12, 'A Longa Viagem a um Pequeno Planeta Hostil', 'Becky Chambers', 2014, 1, 'Você nem imagina os mistérios que existem do outro lado do Universo. Se tiver coragem de desbravá-los, é melhor se preparar. Esta não será uma jornada rápida e os perigos podem surgir a cada momento, de onde menos se espera.A boa notícia é que você não estará sozinho. Milhares de leitores em todo o mundo já embarcaram nas páginas desta que é A LONGA VIAGEM A UM PEQUENO PLANETA HOSTIL.EMBARQUE NESSA VIAGEMO livro de Becky Chambers é um marco recente no universo da ficção científica. Lançado originalmente através de financiamento coletivo pela plataforma Kickstarter, ele conquistou a crítica especializada e os ainda mais exigentes fãs do gênero, sendo indicado para prêmios respeitados, como o Arthur C. Clarke Award e o Hugo Award.Um dos motivos do sucesso de A LONGA VIAGEM A UM PEQUENO PLANETA HOSTIL é a abordagem da história. Elementos essenciais em qualquer narrativa sci-fi estão muito bem representados, como a precisão científica e suas possíveis implicações políticas. O gatilho principal é a construção de um túnel espacial que permitirá ao pequeno planeta do título participar de uma aliança galáctica.Mas o que realmente torna único esse romance on the road futurístico e muito divertido são seus personagens. Instigantes, complexos, tridimensionais. A autora optou por contar a história de gente como a gente ― ainda que nem todos sejam terráqueos, ou mesmo humanos.A tripulação da nave espacial Andarilha é composta por indivíduos de planetas, espécies e gêneros diferentes, incluindo uma piloto reptiliana, uma estagiária nascida nas colônias de Marte e um médico de gênero fluido, que transita entre o masculino e o feminino ao longo da vida.Temas como amizade, racismo, poliamor, força feminina e novos conceitos de família fazem parte do universo do livro, assim como cada vez mais fazem parte do nosso mundo.Becky Chambers segue os passos da pioneira Ursula K. Le Guin (A Mão Esquerda da Escuridão e Despossuídos), e inclusive presta homenagem à inventora do ansible, um dispositivo de comunicação interplanetária, em sua obra. A visão feminina e acurada de autoras como Becky e Ursula permite desconstruir velhos clichês e quem sai ganhando são os amantes da literatura sci-fi ― de todos os gêneros e espécies.Outras fontes ajudaram a formar a autora de A LONGA VIAGEM A UM PEQUENO PLANETA HOSTIL ― Carl Sagan e Star Trek, por exemplo. Mas certamente suas influências estavam em casa. Becky é filha de um casal de cientistas espaciais e neta de um dos participantes dos projetos Apollo da Nasa. A ciência é algo importante na família.A LONGA VIAGEM A UM PEQUENO PLANETA HOSTIL é o primeiro livro de ficção científica da linha DarkLove. Livros escritos por autoras com grandes histórias para contar, prontas para desbravar novos mundos. E ele consolida a DarkSide® Books no fantástico universo de sci-fi. A editora já lançou Star Wars: A Trilogia, novelização dos três primeiros filmes da saga, e O Homem que Caiu na Terra (1963), de Walter Tevis, romance que deu origem ao primeiro filme de David Bowie como autor, dirigido por Nicolas Roeg em 1976.\r\n', 0x433a78616d70706874646f637356656e7573436170617331322e2061206c6f6e67612076696167656d206120756d2070657175656e6f20706c616e65746120686f7374696c2e6a7067),
(13, 'A Cidade e a Cidade', 'China Miéville', 2009, 1, 'Quando o corpo de uma mulher assassinada é encontrado na decadente cidade de Beszel, em algum lugar nos confins da Europa, parece apenas mais um caso trivial para o Inspetor Tyador Borlú, do Esquadrão de Crimes Extremos. Mas, à medida que avança a investigação, as evidências começam a apontar para conspirações muito mais estranhas e mortais do que ele poderia supor. Logo seu trabalho o coloca, e aqueles ao seu redor, em perigo e Borlú deve viajar à única metrópole na Terra tão estranha quanto a sua, por meio de uma fronteira sem igual.\r\nEm uma envolvente e premiada narrativa, híbrido de thriller policial e ficção científica, aos poucos descobrimos que a jovem assassinada tinha envolvimento com a agitação política e cultural entre Beszel e sua \"cidade gêmea\", Ul Quoma. As duas cidades ocupam o mesmo espaço geográfico, mas constituem nações diferentes, monitoradas por um poder secreto conhecido como \"Brecha\". O habitante de uma cidade é educado desde a infância a \"desver\" a outra cidade, seus habitantes, suas construções e os eventos que lá ocorrem. Em ambas as cidades, ignorar a separação, mesmo sem querer, é considerado um crime terrível, ainda mais grave do que cometer um assassinato.\r\nA cidade & a cidade é o livro de estreia de China Miéville na Boitempo, que publicará todos os seus romances no Brasil. Uma narrativa que arrebatou a crítica internacional e ecoa George Orwell, Franz Kafka, Raymond Chandler, Bruno Schulz e Philip K. Dick para tecer um comentário afiado, criativo e emocionante sobre as cidades e a tendência de vermos apenas o que queremos. A tradução é de Fábio Fernandes, especialista em ficção científica e cultura digital e responsável por importantes traduções de clássicos do gênero, como Laranja mecânica, 2001: uma odisseia no espaço e Neuromancer. A ilustração da capa é de Fábio Cobiaco.\r\n.', 0x433a78616d70706874646f637356656e7573436170617331332e412063696461646520652061206369646164652e6a7067),
(14, 'A Fênix Exultante', 'Jo Walton', 2019, 1, ' A continuação triunfante da maior saga futurista do momento. Por seu crime, Phaethon foi exilado da Golden Ecumene, uma utopia que se tornou realidade. Despojado de todos os seus bens, ninguém pode oferecer-lhe ou vender-lhe quaisquer bens ou serviços sem correr o risco de sofrer a mesma punição. Sem amigos, sem possibilidades, perseguido pelos misteriosos agentes que desejam a sua queda, Phaeton não desiste: a sua única esperança é seguir a sugestão enigmática do Cão Sophotec e chegar à cidade de Talaimannar, onde uma sociedade de despossuídos poderá manter a chave para devolvê-lo ao seu devido lugar e finalmente colocá-lo no controle de sua nave, a Fênix Exultante. John C. Wright recapitula quase um século de tradição de ficção científica, de Olaf Stapledon a Jack Vance, de Alfred Bester a Gene Wolfe, e de Cordwainer Smith a Roger Zelazny, na trilogia mais importante do novo milénio. “Esta é a saga mais épica que você pode encontrar hoje, repleta de conceitos incríveis e superciência envolvente, digna do melhor da era de ouro da ficção científica, mas executada com atenção aos detalhes e verossimilhança que a eleva.” muito acima. os outros.\" SFRevu \"A extraordinária ópera espacial do futuro distante continua. Engenhosa, inventiva, labiríntica, com um elenco de primeira linha, a criação de Wright torna-se cada vez mais viciante.\" Kirkus Reviews \"Phoenix Ecstatic mantém a avalanche de invenções científicas, diálogos espirituosos e elegantes e reflexões sérias sobre grandes ideias sociais e políticas que começaram na Idade de Ouro.\" Russel Letson, Locus', ''),
(15, 'Persepolis Rising', 'James S.A. Corey', 2017, 1, 'Na rede de mil sóis da expansão da humanidade, novos mundos colónias estão a lutar para encontrar o seu caminho. Cada novo planeta vive no limite entre o colapso e o espanto, e a tripulação da envelhecida nave Rocinante está mais do que ocupada em manter a frágil paz.\r\nNo vasto espaço entre a Terra e Júpiter, os planetas interiores e a cintura formaram uma aliança hesitante e incerta, ainda assombrada por uma história de guerras e preconceitos. No mundo colonial perdido da Lacônia, um inimigo oculto tem uma nova visão para toda a humanidade e o poder de aplicá-la.\r\nAs novas tecnologias entram em conflito com as antigas, à medida que a história dos conflitos humanos regressa aos seus antigos padrões de guerra e subjugação. Mas a natureza humana não é o único inimigo e as forças desencadeadas têm o seu próprio preço. Um preço que mudará a forma da humanidade – e do Rocinante – inesperadamente e para sempre\r\n', 0x433a78616d70706874646f637356656e7573436170617331352e205065727365706f6c69732e6a7067),
(16, 'O Problema dos Três Corpos', 'Cixin Liu', 2008, 1, 'China, final dos anos 1960. Enquanto o país inteiro está sendo devastado pela violência da Revolução Cultural, um pequeno grupo de astrofísicos, militares e engenheiros começa um projeto ultrassecreto envolvendo ondas sonoras e seres extraterrestres. Uma decisão tomada por um desses cientistas mudará para sempre o destino da humanidade e, cinquenta anos depois, uma civilização alienígena a beira do colapso planeja uma invasão. O problema dos três corpos é uma crônica da marcha humana em direção aos confins do universo. Uma clássica história de ficção científica, no melhor estilo de Arthur C. Clarke. Um jogo envolvente em que a humanidade tem tudo a perder.', 0x433a78616d70706874646f637356656e7573436170617331362e4f2070726f626c656d6120646f73203320636f72706f732e6a7067),
(17, 'Aniquilação', 'Jeff VanderMeer', 2014, 1, 'A Área X está isolada do restante do mundo há décadas, e a natureza tomou para si os últimos vestígios da presença humana. Uma primeira expedição de reconhecimento voltou de lá relatando uma terra intocada, um paraíso edênico; a segunda terminou em suicídio em massa; a terceira, em um tiroteio dentro do próprio grupo. Até que os membros da décima primeira expedição retornaram como meras sombras do que eram antes e, após algumas semanas, morreram de câncer. Em Aniquilação, primeiro volume da trilogia Comando Sul, o leitor se junta à décima segunda expedição.\nO novo grupo é formado por quatro mulheres: uma antropóloga, uma topógrafa, uma psicóloga — líder da missão — e uma bióloga, a narradora do livro. Seus objetivos são mapear o terreno, identificar todas as mudanças ambientais, monitorar as relações entre elas próprias e, acima de tudo, não se contaminarem. As mulheres atravessam a fronteira esperando o inesperado... e é exatamente isso o que encontram. Mas o que de fato vai definir os rumos da expedição não é o que está lá, e sim o que elas trazem consigo desde o outro lado da fronteira e os segredos que guardam umas das outras.\nA Área X está isolada do restante do mundo há décadas, e a natureza tomou para si os últimos vestígios da presença humana. Uma primeira expedição de reconhecimento voltou de lá relatando uma terra intocada, um paraíso edênico; a segunda terminou em suicídio em massa; a terceira, em um tiroteio dentro do próprio grupo. Até que os membros da décima primeira expedição retornaram como meras sombras do que eram antes e, após algumas semanas, morreram de câncer. Em Aniquilação, primeiro volume da trilogia Comando Sul, o leitor se junta à décima segunda expedição.\nO novo grupo é formado por quatro mulheres: uma antropóloga, uma topógrafa, uma psicóloga — líder da missão — e uma bióloga, a narradora do livro. Seus objetivos são mapear o terreno, identificar todas as mudanças ambientais, monitorar